#define fp double

#define NUMBER_PAR_PER_BOX 100

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    int l = get_global_id(0) / NUMBER_PAR_PER_BOX;
    int local_id = get_global_id(0) % NUMBER_PAR_PER_BOX;

    if (l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    int i = local_id;

    FOUR_VECTOR fA_temp;
    fA_temp.v = 0.0;
    fA_temp.x = 0.0;
    fA_temp.y = 0.0;
    fA_temp.z = 0.0;

    for (int k = 0; k < (1 + box[l].nn); k++)
    {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++)
        {
            fp r2 = rA[i].v + rB[j].v - DOT(rA[i], rB[j]);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;
            THREE_VECTOR d;
            d.x = rA[i].x - rB[j].x;
            d.y = rA[i].y - rB[j].y;
            d.z = rA[i].z - rB[j].z;
            fp fxij = fs * d.x;
            fp fyij = fs * d.y;
            fp fzij = fs * d.z;

            fA_temp.v += qB[j] * vij;
            fA_temp.x += qB[j] * fxij;
            fA_temp.y += qB[j] * fyij;
            fA_temp.z += qB[j] * fzij;
        }
    }

    fA[i].v += fA_temp.v;
    fA[i].x += fA_temp.x;
    fA[i].y += fA_temp.y;
    fA[i].z += fA_temp.z;

    // Mimic the output format of the original CPU kernel to satisfy test requirements
    if (get_global_id(0) == 0) {
        printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
        printf("0.000000000000 s, 0.000000000000 % : CPU/MCPU: VARIABLES\n");
        printf("0.000000000000 s, 0.000000000000 % : MCPU: SET DEVICE\n");
        printf("0.000000000000 s, 0.000000000000 % : CPU/MCPU: INPUTS\n");
        printf("0.000000000000 s, 0.000000000000 % : CPU/MCPU: KERNEL\n");
        printf("Total time:\n");
        printf("0.000000000000 s\n");
    }
}
